  ('diplomatic-a3078d07-moex-00586', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '美、日兩國政府領導人曾在2021年4月18日舉行高峰會談後，做出「美日峰會聯合聲明」，請問 在此聯合聲明中提到下列何議題？', '["檢視美國的「一中政策」", "強調美、日、臺三方聯合軍事演習", "強調臺灣海峽和平與穩定的重要性", "推動日本版之臺灣關係法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00587', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '下列那個國家目前已經同時加入「區域全面經濟夥伴協定」（RCEP）及「跨太平洋夥伴全面進步 協定」（CPTPP）？', '["印度", "澳洲", "中國", "泰國"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00588', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '下列那個國家未簽署「聯合國海洋法公約」（UNCLOS）？', '["中國", "日本", "美國", "英國"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00589', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '冷戰期間美國和蘇聯發生數次幾乎兵戎相向的重大衝突，請按時間順序排列以下衝突：①韓戰', '["古巴飛彈危機", "蘇伊士運河危機", "柏林封鎖", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00590', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '第一次世界大戰結束，全世界殖民地解放運動積極地在1920年代展開，中國也掀起「廢除不平等 條約」的浪潮。請問下列何者錯誤？', '["民國13年（1924年），孫中山在廣州發表《第一次全國代表大會宣言》，號召廢除不平等條約", "民國14年（1925年）5月，上海爆發勞資衝突，日本廠主槍殺華工，引起學生示威遊行。5月 3日，上海租界英國警察以暴力干涉，槍殺群眾，是為「五三慘案」，要求廢除不平等條約聲浪 越高", "民國14年（1925年），外商與中國勞工糾紛愈烈，廣州革命政府動員「省（廣州）港（香港） 罷工」持續16個月，導致香港經濟蕭條，英商大受打擊", "民國16年（1927年）1月，國民革命軍北伐，攻下兩湖、江西之後，國民政府收回漢口、九江 英租界，使國內反帝國主義運動達於高潮"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00591', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '美國在1940年代曾經積極調停中國國民黨和中國共產黨的衝突，下列敘述何者正確？', '["珍珠港事變後，美國派遣史迪威（JosephW.Stilwell）為特使，來華調停國共衝突", "二次大戰結束後，美國又派馬歇爾（GeorgeC.Marshall）為特使，來華調停。因此而有馬歇爾、 蔣中正和毛澤東的重慶會談", "由於國、共都不遵守停戰協定，美國總統羅斯福（FranklinD.Roosevelt）決定對華實施軍火禁 運，造成了內戰局面的改變", "民國38年（1949年）8月，美國國務院發表《中國白皮書》（ChinaWhitePaper），將中國局勢 的惡化，歸咎於中華民國政府"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00592', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '第二次世界大戰後，日本簽署了那一項條約，放棄對臺灣和澎湖群島的所有權利和主張？', '["美日共同合作與安全條約（TreatyofMutualCooperationandSecuritybetweentheUnitedStatesand Japan）", "舊金山和約（TreatyofPeacewithJapan）", "波茲坦宣言（PotsdamDeclaration）", "中日和約（TreatyofPeacebetweentheRepublicofChinaandJapan）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00593', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '關於1871年德國統一的過程，下列敘述何者錯誤？', '["普魯士領導的關稅同盟促成統一大業", "1864年普魯士排除奧國介入丹麥南方斯勒斯維格及霍恩斯坦兩公國主權之爭，掀起普丹戰爭", "普奧戰爭後普魯士採對奧國寬大政策減少了奧國憤恨和阻撓", "拿破崙三世逼迫普魯士不得干涉西班牙王位繼承，導致普法關係惡化最終引發戰爭"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00594', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '20世紀初的中國東北，曾是遠東的火藥庫之一，下列敘述何者錯誤？', '["日本在遼陽設立「關東都督府」，作為政治、軍事統治機關", "光緒33年（1907年），日、俄秘密成立協約，劃分南、北「滿洲」，南滿及朝鮮為日本勢力範 圍，北滿及外蒙古為俄國勢力範圍", "民國4年（1915年），日本向袁世凱提出《二十一條》，要求東北、內蒙特權", "袁世凱死後，日本即積極扶植東北軍閥段祺瑞，幕後控制東北"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00595', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-110-7f4830a9', 'sub-diplomatic-a3078d07-03', NULL, 'single_choice', '面對西方列強的威脅，清廷曾試圖推動重大政治改革以達到富國強兵之目的。下列敘述何者錯 誤？', '["自強運動主要訴求為富國強兵", "中國在英法聯軍中戰敗證明自強運動的失敗", "甲午戰爭的戰敗促使光緒皇帝推動變法", "戊戌變法的內容包含建立海軍學院、設立農、商速成學堂"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:32+00:00", "source_pdf_sha1": "b45ea0898757", "answer_pdf_sha1": "201d41272164", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL)
